{% extends "base.html" %}

{% block title %}Forgot password -- Todo List{% endblock %}

{% block content %}
<div class="auth-form">
    <h1>Forgot password</h1>
    <p>Password reset is coming soon. For now, please try to remember your password or create a new account.</p>
    <p class="auth-form__footer">
        <a href="/login">Back to sign in</a>
    </p>
</div>
{% endblock %}

